(function () {
      var previewEmpty = new URLSearchParams(window.location.search).get('empty');
      var showEmptyPreview = previewEmpty === '1' || previewEmpty === 'true';

      if (!showEmptyPreview) {
        DCEvents.fillContainer('home-invited-grid', { category: 'invited', limit: 2, detailContext: 'explore' });
        DCEvents.fillContainer('home-today-grid', { category: 'joined-today', limit: 2, detailContext: 'joined' });
        DCEvents.fillContainer('home-upcoming-grid', { category: 'joined-upcoming', limit: 2, detailContext: 'joined' });
        DCEvents.fillContainer('home-past-grid', { category: 'joined-past', limit: 2, detailContext: 'joined' });
      }

      function showEmptyState(containerId, title, description) {
        var container = document.getElementById(containerId);
        if (!container || container.children.length > 0) return;

        var emptyState = document.createElement('div');
        emptyState.className = 'home-empty-state';
        emptyState.setAttribute('role', 'status');
        emptyState.innerHTML =
          '<img class="home-empty-state__icon" src="/no-event.svg" width="160" height="160" alt="" aria-hidden="true" />' +
          '<h3 class="home-empty-state__title">' + title + '</h3>' +
          '<p class="home-empty-state__description">' + description + '</p>';

        container.appendChild(emptyState);
      }

      showEmptyState(
        'home-invited-grid',
        'No event invitations yet.',
        'You do not have any event invitations right now. New invitations will appear here.'
      );
      showEmptyState(
        'home-today-grid',
        'No events scheduled for today.',
        'You currently have no events happening today. Check back later or join a new event to get started.'
      );
      showEmptyState(
        'home-upcoming-grid',
        'No upcoming events found.',
        'There are no scheduled events coming up. Join an event to stay connected and start planning ahead.'
      );
      showEmptyState(
        'home-past-grid',
        'No past events available.',
        'You do not have any completed events yet. Past events will appear here once they have ended.'
      );

      var viewYear;
      var viewMonth;
      var today = new Date();
      var todayY = today.getFullYear();
      var todayM = today.getMonth();
      var todayD = today.getDate();

      var monthNames = ['January', 'February', 'March', 'April', 'May', 'June',
        'July', 'August', 'September', 'October', 'November', 'December'];
      var monthShort = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
        'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

      function initTodayCards() {
        /* Event cards now come from shared events-data.js */
      }

      function renderCalendar(year, month) {
        viewYear = year;
        viewMonth = month;

        var title = document.getElementById('calendar-title');
        var daysEl = document.getElementById('calendar-days');
        title.textContent = monthNames[month] + ' ' + year;
        daysEl.innerHTML = '';

        var first = new Date(year, month, 1);
        var last = new Date(year, month + 1, 0);
        var startPad = (first.getDay() + 6) % 7;

        for (var i = 0; i < startPad; i++) {
          var empty = document.createElement('span');
          empty.className = 'calendar__day calendar__day--empty';
          empty.textContent = '0';
          daysEl.appendChild(empty);
        }

        for (var d = 1; d <= last.getDate(); d++) {
          var cell = document.createElement('span');
          cell.className = 'calendar__day';
          cell.textContent = d;
          if (year === todayY && month === todayM && d === todayD) {
            cell.classList.add('calendar__day--today');
          }
          daysEl.appendChild(cell);
        }
      }

      document.getElementById('cal-prev').addEventListener('click', function () {
        var m = viewMonth - 1;
        var y = viewYear;
        if (m < 0) { m = 11; y--; }
        renderCalendar(y, m);
      });

      document.getElementById('cal-next').addEventListener('click', function () {
        var m = viewMonth + 1;
        var y = viewYear;
        if (m > 11) { m = 0; y++; }
        renderCalendar(y, m);
      });

      var app = document.querySelector('.app');
      var toggle = document.getElementById('sidebar-toggle');
      var collapse = document.getElementById('sidebar-collapse');
      var storageKey = 'dc_sidebar_collapsed';
      function setSidebarCollapsed(collapsed) {
        app.classList.toggle('is-sidebar-collapsed', collapsed);
        localStorage.setItem(storageKey, collapsed);
      }
      if (localStorage.getItem(storageKey) === 'true' && window.innerWidth > 900) {
        setSidebarCollapsed(true);
      }
      collapse.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(true);
      });
      toggle.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(false);
      });

      initTodayCards();
      renderCalendar(todayY, todayM);
    })();
